import type { ComponentProps } from 'react';
import { Menu as MenuPrimitive } from '@base-ui/react/menu';
import { clsx } from 'clsx';
import {
  CheckIcon,
  ChevronDownIcon,
  ChevronRightIcon,
  PopupArrowIcon,
} from '@/lib/moduix/icons/ui';
import { mergeClassName } from '@/lib/moduix/mergeClassName';
import styles from './Menu.module.css';

export type MenuPositionerProps = Pick<
  MenuPrimitive.Positioner.Props,
  | 'side'
  | 'sideOffset'
  | 'align'
  | 'alignOffset'
  | 'arrowPadding'
  | 'collisionAvoidance'
  | 'collisionBoundary'
  | 'collisionPadding'
>;

export type MenuIndicatorPosition = 'start' | 'end';
export type MenuContentProps = MenuPrimitive.Popup.Props &
  MenuPositionerProps & {
    showArrow?: boolean;
  };
export type MenuRadioItemProps = MenuPrimitive.RadioItem.Props & {
  indicator?: MenuIndicatorPosition;
};
export type MenuCheckboxItemProps = MenuPrimitive.CheckboxItem.Props & {
  indicator?: MenuIndicatorPosition;
};

const MENU_CONTENT_SIDE_OFFSET = 8;
const Menu = MenuPrimitive.Root;
const MenuSubmenu = MenuPrimitive.SubmenuRoot;
const createMenuHandle = MenuPrimitive.createHandle;

function MenuTrigger({ className, render, ...props }: MenuPrimitive.Trigger.Props) {
  const triggerClassName = render ? className : mergeClassName(className, styles.trigger);

  return (
    <MenuPrimitive.Trigger
      data-slot="menu-trigger"
      render={render}
      className={triggerClassName}
      {...props}
    />
  );
}

function MenuTriggerIcon({ className, children, ...props }: ComponentProps<'span'>) {
  return (
    <span data-slot="menu-trigger-icon" className={clsx(styles.triggerIcon, className)} {...props}>
      {children ?? <ChevronDownIcon className={styles.iconSvg} />}
    </span>
  );
}

function MenuPortal(props: MenuPrimitive.Portal.Props) {
  return <MenuPrimitive.Portal data-slot="menu-portal" {...props} />;
}

function MenuBackdrop({ className, ...props }: MenuPrimitive.Backdrop.Props) {
  return (
    <MenuPrimitive.Backdrop
      data-slot="menu-backdrop"
      className={mergeClassName(className, styles.backdrop)}
      {...props}
    />
  );
}

function MenuPositioner({ className, ...props }: MenuPrimitive.Positioner.Props) {
  return (
    <MenuPrimitive.Positioner
      data-slot="menu-positioner"
      className={mergeClassName(className, styles.positioner)}
      {...props}
    />
  );
}

function MenuPopup({ className, ...props }: MenuPrimitive.Popup.Props) {
  return (
    <MenuPrimitive.Popup
      data-slot="menu-popup"
      className={mergeClassName(className, styles.popup)}
      {...props}
    />
  );
}

function MenuArrow({ className, children, ...props }: MenuPrimitive.Arrow.Props) {
  return (
    <MenuPrimitive.Arrow
      data-slot="menu-arrow"
      className={mergeClassName(className, styles.arrow)}
      {...props}
    >
      {children ?? <ArrowSvg className={styles.arrowSvg} />}
    </MenuPrimitive.Arrow>
  );
}

function MenuViewport({ className, ...props }: MenuPrimitive.Viewport.Props) {
  return (
    <MenuPrimitive.Viewport
      data-slot="menu-viewport"
      className={mergeClassName(className, styles.viewport)}
      {...props}
    />
  );
}

function MenuContent({
  className,
  children,
  showArrow = false,
  side,
  sideOffset = MENU_CONTENT_SIDE_OFFSET,
  align,
  alignOffset,
  arrowPadding,
  collisionAvoidance,
  collisionBoundary,
  collisionPadding,
  ...props
}: MenuContentProps) {
  return (
    <MenuPortal>
      <MenuPositioner
        side={side}
        sideOffset={sideOffset}
        align={align}
        alignOffset={alignOffset}
        arrowPadding={arrowPadding}
        collisionAvoidance={collisionAvoidance}
        collisionBoundary={collisionBoundary}
        collisionPadding={collisionPadding}
      >
        <MenuPopup className={className} {...props}>
          {showArrow ? <MenuArrow /> : null}
          {children}
        </MenuPopup>
      </MenuPositioner>
    </MenuPortal>
  );
}

function MenuSubmenuContent({
  sideOffset = getSubmenuOffset,
  alignOffset = getSubmenuOffset,
  ...props
}: MenuContentProps) {
  return <MenuContent sideOffset={sideOffset} alignOffset={alignOffset} {...props} />;
}

function MenuItem({ className, ...props }: MenuPrimitive.Item.Props) {
  return (
    <MenuPrimitive.Item
      data-slot="menu-item"
      className={mergeClassName(className, styles.item)}
      {...props}
    />
  );
}

function MenuLinkItem({ className, ...props }: MenuPrimitive.LinkItem.Props) {
  return (
    <MenuPrimitive.LinkItem
      data-slot="menu-link-item"
      className={mergeClassName(className, styles.linkItem)}
      {...props}
    />
  );
}

function MenuSeparator({ className, ...props }: MenuPrimitive.Separator.Props) {
  return (
    <MenuPrimitive.Separator
      data-slot="menu-separator"
      className={mergeClassName(className, styles.separator)}
      {...props}
    />
  );
}

function MenuGroup({ className, ...props }: MenuPrimitive.Group.Props) {
  return (
    <MenuPrimitive.Group
      data-slot="menu-group"
      className={mergeClassName(className, styles.group)}
      {...props}
    />
  );
}

function MenuGroupLabel({ className, ...props }: MenuPrimitive.GroupLabel.Props) {
  return (
    <MenuPrimitive.GroupLabel
      data-slot="menu-group-label"
      className={mergeClassName(className, styles.groupLabel)}
      {...props}
    />
  );
}

function MenuSubmenuTrigger({ className, ...props }: MenuPrimitive.SubmenuTrigger.Props) {
  return (
    <MenuPrimitive.SubmenuTrigger
      data-slot="menu-submenu-trigger"
      className={mergeClassName(className, styles.submenuTrigger)}
      {...props}
    />
  );
}

function MenuSubmenuTriggerIcon({ className, children, ...props }: ComponentProps<'span'>) {
  return (
    <span
      data-slot="menu-submenu-trigger-icon"
      className={clsx(styles.submenuTriggerIcon, className)}
      {...props}
    >
      {children ?? <ChevronRightIcon className={styles.iconSvg} />}
    </span>
  );
}

function MenuRadioGroup({ className, ...props }: MenuPrimitive.RadioGroup.Props) {
  return (
    <MenuPrimitive.RadioGroup
      data-slot="menu-radio-group"
      className={mergeClassName(className, styles.radioGroup)}
      {...props}
    />
  );
}

function MenuRadioItem({ className, indicator, ...props }: MenuRadioItemProps) {
  return (
    <MenuPrimitive.RadioItem
      data-slot="menu-radio-item"
      data-indicator-position={indicator}
      className={mergeClassName(className, styles.radioItem)}
      {...props}
    />
  );
}

function MenuRadioItemIndicator({
  className,
  children,
  ...props
}: MenuPrimitive.RadioItemIndicator.Props) {
  return (
    <MenuPrimitive.RadioItemIndicator
      data-slot="menu-radio-item-indicator"
      className={mergeClassName(className, styles.radioItemIndicator)}
      {...props}
    >
      {children ?? <CheckIcon className={styles.itemIndicatorIcon} />}
    </MenuPrimitive.RadioItemIndicator>
  );
}

function MenuCheckboxItem({ className, indicator, ...props }: MenuCheckboxItemProps) {
  return (
    <MenuPrimitive.CheckboxItem
      data-slot="menu-checkbox-item"
      data-indicator-position={indicator}
      className={mergeClassName(className, styles.checkboxItem)}
      {...props}
    />
  );
}

function MenuCheckboxItemIndicator({
  className,
  children,
  ...props
}: MenuPrimitive.CheckboxItemIndicator.Props) {
  return (
    <MenuPrimitive.CheckboxItemIndicator
      data-slot="menu-checkbox-item-indicator"
      className={mergeClassName(className, styles.checkboxItemIndicator)}
      {...props}
    >
      {children ?? <CheckIcon className={styles.itemIndicatorIcon} />}
    </MenuPrimitive.CheckboxItemIndicator>
  );
}

function MenuItemText({ className, ...props }: ComponentProps<'span'>) {
  return (
    <span data-slot="menu-item-text" className={clsx(styles.itemText, className)} {...props} />
  );
}

function MenuItemTextContent({ className, ...props }: ComponentProps<'span'>) {
  return (
    <span
      data-slot="menu-item-text-content"
      className={clsx(styles.itemTextContent, className)}
      {...props}
    />
  );
}

function MenuItemTextIcon({ className, ...props }: ComponentProps<'span'>) {
  return (
    <span
      data-slot="menu-item-text-icon"
      className={clsx(styles.itemTextIcon, className)}
      {...props}
    />
  );
}

function MenuItemTextLabel({ className, ...props }: ComponentProps<'span'>) {
  return (
    <span
      data-slot="menu-item-text-label"
      className={clsx(styles.itemTextLabel, className)}
      {...props}
    />
  );
}

function MenuItemShortcut({ className, ...props }: ComponentProps<'span'>) {
  return (
    <span
      data-slot="menu-item-shortcut"
      className={clsx(styles.itemShortcut, className)}
      {...props}
    />
  );
}

function getSubmenuOffset({ side }: { side: MenuPrimitive.Positioner.Props['side'] }) {
  return side === 'top' || side === 'bottom' ? 4 : -4;
}

function ArrowSvg(props: ComponentProps<'svg'>) {
  return (
    <PopupArrowIcon
      fillClassName={styles.arrowFill}
      outerStrokeClassName={styles.arrowOuterStroke}
      innerStrokeClassName={styles.arrowInnerStroke}
      {...props}
    />
  );
}

export {
  Menu,
  MenuSubmenu,
  createMenuHandle,
  MenuTrigger,
  MenuTriggerIcon,
  MenuPortal,
  MenuBackdrop,
  MenuPositioner,
  MenuPopup,
  MenuArrow,
  MenuViewport,
  MenuContent,
  MenuSubmenuContent,
  MenuItem,
  MenuLinkItem,
  MenuSeparator,
  MenuGroup,
  MenuGroupLabel,
  MenuSubmenuTrigger,
  MenuSubmenuTriggerIcon,
  MenuRadioGroup,
  MenuRadioItem,
  MenuRadioItemIndicator,
  MenuCheckboxItem,
  MenuCheckboxItemIndicator,
  MenuItemText,
  MenuItemTextContent,
  MenuItemTextIcon,
  MenuItemTextLabel,
  MenuItemShortcut,
};

@layer ui.components {
  .trigger {
    box-sizing: border-box;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: var(--menu-trigger-gap, 0.5rem);
    min-height: var(--menu-trigger-height, var(--size-lg));
    margin: 0;
    padding: var(--menu-trigger-padding-y, 0.5rem) var(--menu-trigger-padding-x, 0.875rem);
    border: var(--menu-trigger-border-width, var(--border-width-sm)) solid
      var(--menu-trigger-border-color, var(--color-border));
    border-radius: var(--menu-trigger-radius, var(--radius-md));
    background-color: var(--menu-trigger-bg, var(--color-background));
    color: var(--menu-trigger-color, var(--color-foreground));
    font: inherit;
    font-size: var(--menu-trigger-font-size, var(--text-md));
    line-height: var(--menu-trigger-line-height, var(--line-height-text-md));
    user-select: none;
    outline: 0;
    cursor: pointer;
    transition:
      background-color var(--menu-transition, var(--transition-default)),
      border-color var(--menu-transition, var(--transition-default)),
      color var(--menu-transition, var(--transition-default));

    @media (hover: hover) {
      &:hover {
        background-color: var(--menu-trigger-bg-hover, var(--color-accent));
      }
    }

    &:active,
    &[data-popup-open] {
      background-color: var(
        --menu-trigger-bg-active,
        var(--menu-trigger-bg-hover, var(--color-accent))
      );
    }

    &:focus-visible {
      outline: var(
          --menu-focus-ring-width,
          var(--menu-trigger-border-width, var(--border-width-sm))
        )
        solid var(--menu-focus-ring-color, var(--color-ring));
      outline-offset: calc(
        var(--menu-focus-ring-width, var(--menu-trigger-border-width, var(--border-width-sm))) * -1
      );
    }

    &[data-disabled],
    &[disabled] {
      pointer-events: none;
      opacity: var(--menu-disabled-opacity, var(--opacity-disabled));
    }
  }

  .triggerIcon {
    box-sizing: border-box;
    display: inline-flex;
    width: var(--menu-trigger-icon-size, 1rem);
    height: var(--menu-trigger-icon-size, 1rem);
    flex-shrink: 0;
    color: var(--menu-trigger-icon-color, currentColor);
  }

  .iconSvg {
    width: 100%;
    height: 100%;
  }

  .backdrop {
    position: fixed;
    z-index: var(--z-backdrop);
    inset: 0;
    min-height: 100dvh;
    background-color: var(--menu-backdrop-bg, var(--backdrop-bg, var(--color-overlay)));
    backdrop-filter: var(--backdrop-filter, blur(var(--menu-backdrop-blur, 4px)));
    transition:
      opacity var(--menu-backdrop-transition, var(--transition-default)),
      backdrop-filter var(--menu-backdrop-transition, var(--transition-default));

    &[data-starting-style],
    &[data-ending-style] {
      opacity: 0;
      backdrop-filter: none;
    }
  }

  .positioner {
    z-index: var(--z-popup);
    width: var(--positioner-width);
    height: var(--positioner-height);
    max-width: var(--available-width);
    outline: 0;
  }

  .popup {
    position: relative;
    box-sizing: border-box;
    width: var(--popup-width, var(--menu-popup-width, auto));
    height: var(--popup-height, var(--menu-popup-height, auto));
    min-width: min(var(--menu-popup-min-width, 12rem), var(--available-width, 100vw));
    max-width: min(var(--menu-popup-max-width, 20rem), var(--available-width, 100vw));
    max-height: min(var(--menu-popup-max-height, 24rem), var(--available-height, 100dvh));
    overflow: visible;
    padding-block: var(--menu-popup-padding-y, 0.25rem);
    border: 0;
    border-radius: var(--menu-popup-radius, var(--radius-md));
    background-color: var(--menu-popup-bg, var(--color-popover));
    color: var(--menu-popup-color, var(--color-popover-foreground));
    outline: var(--menu-popup-border-width, var(--border-width-sm)) solid
      var(--menu-popup-border-color, var(--color-border));
    box-shadow: var(--menu-popup-shadow, var(--shadow-lg));
    transform-origin: var(--transform-origin);
    transition:
      transform var(--menu-transition, var(--transition-default)),
      opacity var(--menu-transition, var(--transition-default));

    &[data-starting-style],
    &[data-ending-style] {
      opacity: 0;
      transform: scale(var(--menu-popup-scale, var(--scale-popup)));
    }
  }

  .viewport {
    box-sizing: border-box;
    position: relative;
    width: 100%;
    height: 100%;
    max-height: min(var(--menu-popup-max-height, 24rem), var(--available-height, 100dvh));
    overflow: clip;
    padding: 0;
  }

  .arrow {
    display: flex;
    color: var(--menu-popup-bg, var(--color-popover));

    &[data-side='top'] {
      bottom: calc(var(--menu-arrow-size, 0.5rem) * -1);
      rotate: 180deg;
    }

    &[data-side='bottom'] {
      top: calc(var(--menu-arrow-size, 0.5rem) * -1);
      rotate: 0deg;
    }

    &[data-side='left'] {
      right: calc(var(--menu-arrow-inline-offset, 0.8125rem) * -1);
      rotate: 90deg;
    }

    &[data-side='right'] {
      left: calc(var(--menu-arrow-inline-offset, 0.8125rem) * -1);
      rotate: -90deg;
    }
  }

  .arrowSvg {
    display: block;
    width: var(--menu-arrow-width, 1.25rem);
    height: var(--menu-arrow-height, 0.625rem);
    overflow: visible;
  }

  .arrowFill {
    fill: currentColor;
  }

  .arrowOuterStroke {
    fill: var(--menu-arrow-stroke-color, var(--menu-popup-border-color, var(--color-border)));
  }

  .arrowInnerStroke {
    fill: var(--menu-popup-bg, var(--color-popover));
  }

  .item,
  .linkItem,
  .submenuTrigger,
  .radioItem,
  .checkboxItem {
    position: relative;
    box-sizing: border-box;
    min-height: var(--menu-item-height, var(--popup-item-min-height, 2rem));
    margin: 0;
    border: 0;
    outline: 0;
    background-color: var(--menu-item-bg, transparent);
    color: inherit;
    font: inherit;
    font-size: var(--menu-item-font-size, var(--popup-item-font-size, var(--text-sm)));
    line-height: var(
      --menu-item-line-height,
      var(--popup-item-line-height, var(--line-height-text-sm))
    );
    text-decoration: none;
    user-select: none;
    cursor: default;

    &[data-highlighted] {
      z-index: 0;
      color: var(--menu-highlight-color, var(--color-background));
    }

    &[data-popup-open] {
      z-index: 0;
    }

    &[data-highlighted]::before,
    &[data-popup-open]::before {
      content: '';
      z-index: -1;
      position: absolute;
      inset-block: 0;
      inset-inline: var(--menu-highlight-inset-x, var(--popup-highlight-inset-x, var(--spacing-1)));
      border-radius: var(--menu-highlight-radius, var(--popup-highlight-radius, var(--radius-sm)));
    }

    &[data-highlighted]::before {
      background-color: var(--menu-highlight-bg, var(--color-foreground));
    }

    &[data-popup-open]::before {
      background-color: var(--menu-submenu-open-bg, var(--color-accent));
    }

    &[data-highlighted][data-popup-open]::before {
      background-color: var(--menu-highlight-bg, var(--color-foreground));
    }

    &[data-disabled] {
      background-color: var(--menu-item-bg-disabled, var(--menu-item-bg, transparent));
      color: var(--menu-item-disabled-color, var(--color-muted-foreground));
    }

    &[data-disabled],
    &[disabled] {
      pointer-events: none;
      cursor: default;
    }
  }

  .item,
  .linkItem {
    display: flex;
    align-items: center;
    gap: var(--menu-item-gap, var(--spacing-2));
    padding-block: var(--menu-item-padding-y, var(--popup-item-padding-y, 0.5rem));
    padding-inline: var(--menu-item-padding-x-start, var(--popup-item-padding-x-start, 1rem))
      var(--menu-item-padding-x-end, var(--popup-item-padding-x-end, 1rem));
  }

  .submenuTrigger {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: var(--menu-submenu-trigger-gap, var(--spacing-3));
    padding-block: var(--menu-item-padding-y, var(--popup-item-padding-y, 0.5rem));
    padding-inline: var(--menu-item-padding-x-start, var(--popup-item-padding-x-start, 1rem))
      var(--menu-submenu-trigger-padding-x-end, 1rem);
  }

  .submenuTriggerIcon {
    box-sizing: border-box;
    display: inline-flex;
    width: var(--menu-submenu-icon-size, 0.875rem);
    height: var(--menu-submenu-icon-size, 0.875rem);
    flex-shrink: 0;
    color: currentColor;
  }

  .group {
    display: grid;
    padding-block: var(--menu-group-padding-y, 0);
  }

  .groupLabel {
    margin: 0;
    padding-block: var(--menu-group-label-padding-y, var(--popup-group-label-padding-y, 0.35rem));
    padding-inline: var(
        --menu-group-label-padding-x-start,
        var(--popup-group-label-padding-x-start, 0.625rem)
      )
      var(--menu-group-label-padding-x-end, var(--popup-group-label-padding-x-end, 0.75rem));
    color: var(--menu-group-label-color, var(--color-muted-foreground));
    font-size: var(
      --menu-group-label-font-size,
      var(--popup-group-label-font-size, var(--text-xs))
    );
    line-height: var(
      --menu-group-label-line-height,
      var(--popup-group-label-line-height, var(--line-height-text-xs))
    );
    user-select: none;
    cursor: default;
  }

  .radioGroup {
    display: grid;
  }

  .radioItem,
  .checkboxItem {
    display: grid;
    align-items: center;
    gap: var(--menu-check-gap, var(--popup-check-gap, 0.5rem));
    grid-template-columns:
      var(--menu-check-indicator-size, var(--popup-check-indicator-size, 0.75rem))
      1fr;
    padding-block: var(--menu-item-padding-y, var(--popup-item-padding-y, 0.5rem));
    padding-inline: var(--menu-check-padding-x-start, var(--popup-check-padding-x-start, 0.625rem))
      var(--menu-item-padding-x-end, var(--popup-item-padding-x-end, 1rem));

    &[data-indicator-position='end'] {
      grid-template-columns:
        minmax(0, 1fr)
        var(--menu-check-indicator-size, var(--popup-check-indicator-size, 0.75rem));

      & > .itemText {
        grid-column-start: 1;
      }

      & > .radioItemIndicator,
      & > .checkboxItemIndicator {
        grid-column-start: 2;
        justify-self: end;
      }
    }
  }

  .checkboxItem {
    &[data-checked] {
      & > .checkboxItemIndicator {
        background-color: var(
          --menu-checkbox-indicator-bg-checked,
          var(--menu-checkbox-indicator-bg, transparent)
        );
        border-color: var(
          --menu-checkbox-indicator-border-color-checked,
          var(--menu-checkbox-indicator-border-color, currentColor)
        );
      }
    }
  }

  .radioItemIndicator,
  .checkboxItemIndicator {
    grid-column-start: 1;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: var(--menu-check-indicator-size, var(--popup-check-indicator-size, 0.75rem));
    height: var(--menu-check-indicator-size, var(--popup-check-indicator-size, 0.75rem));
  }

  .checkboxItemIndicator {
    border: var(--menu-checkbox-indicator-border-width, 0) solid
      var(--menu-checkbox-indicator-border-color, currentColor);
    border-radius: var(--menu-checkbox-indicator-radius, var(--radius-xs));
    background-color: var(--menu-checkbox-indicator-bg, transparent);
  }

  .itemIndicatorIcon {
    width: 100%;
    height: 100%;
  }

  .itemText {
    grid-column-start: 2;
    min-width: 0;
    overflow: hidden;
  }

  .itemTextContent {
    display: inline-flex;
    align-items: center;
    gap: var(--menu-item-text-content-gap, var(--spacing-2));
    max-width: 100%;
    min-width: 0;
    vertical-align: top;
  }

  .itemTextIcon {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    flex-shrink: 0;
    width: var(--menu-item-text-icon-size, 1rem);
    height: var(--menu-item-text-icon-size, 1rem);
    color: var(--menu-item-text-icon-color, currentColor);
  }

  .itemTextLabel {
    min-width: 0;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  }

  .itemShortcut {
    margin-inline-start: auto;
    padding-inline-start: var(--menu-item-shortcut-padding-x-start, var(--spacing-4));
    color: var(--menu-item-shortcut-color, var(--color-muted-foreground));
    font-size: var(--menu-item-shortcut-font-size, var(--text-xs));
    line-height: var(--menu-item-shortcut-line-height, var(--line-height-text-xs));
    white-space: nowrap;
  }

  .separator {
    box-sizing: border-box;
    height: var(--menu-separator-height, var(--border-width-sm));
    margin-block: var(--menu-separator-margin-y, var(--popup-separator-margin-y, 0.375rem));
